import java.util.Scanner;

public class SecureBufferHandling {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");

        String name = scanner.nextLine();
        int bufferSize = 10; // Maximum buffer size

        // Ensure that input length does not exceed buffer size
        if (name.length() > bufferSize) {
            name = name.substring(0, bufferSize); // Trim input if longer than buffer size
        }

        char[] buffer = new char[bufferSize]; // Dynamic buffer

        // Copy user input into the buffer
        name.getChars(0, name.length(), buffer, 0);

        System.out.println("Hello, " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
